    14|/// UIView whose backing layer is an AVPlayerLayer (aspect-fill video).
    15|final class PlayerContainerView: UIView {
    16|    override static var layerClass: AnyClass { AVPlayerLayer.self }
    17|
    18|    var playerLayer: AVPlayerLayer {
    19|        guard let layer = layer as? AVPlayerLayer else {
    20|            fatalError("PlayerContainerView backing layer must be AVPlayerLayer")
    21|        }
    22|        return layer
    23|    }
