    26|/// Muted, seamlessly-looping autoplay video — the Instagram card behaviour.
    27|struct LoopingVideoView: UIViewRepresentable {
    28|    let url: URL
    29|    let isMuted: Bool
    30|
    31|    func makeCoordinator() -> Coordinator {
    32|        Coordinator()
    33|    }
    34|
    35|    func makeUIView(context: Context) -> PlayerContainerView {
    36|        let view = PlayerContainerView()
    37|        view.backgroundColor = .black
    38|        view.playerLayer.videoGravity = .resizeAspectFill
    39|        context.coordinator.configure(url: url, layer: view.playerLayer)
    40|        context.coordinator.player?.isMuted = isMuted
    41|        return view
    42|    }
    43|
    44|    func updateUIView(_ uiView: PlayerContainerView, context: Context) {
    45|        context.coordinator.player?.isMuted = isMuted
    46|    }
    47|
    48|    static func dismantleUIView(_ uiView: PlayerContainerView, coordinator: Coordinator) {
    49|        coordinator.teardown()
    50|    }
    51|
    52|    final class Coordinator {
    53|        var player: AVQueuePlayer?
    54|        private var looper: AVPlayerLooper?
    55|
    56|        func configure(url: URL, layer: AVPlayerLayer) {
    57|            let item = AVPlayerItem(url: url)
    58|            let queuePlayer = AVQueuePlayer()
    59|            queuePlayer.preventsDisplaySleepDuringVideoPlayback = false
    60|            looper = AVPlayerLooper(player: queuePlayer, templateItem: item)
    61|            layer.player = queuePlayer
    62|            queuePlayer.play()
    63|            player = queuePlayer
    64|        }
    65|
    66|        func teardown() {
    67|            player?.pause()
    68|            looper = nil
    69|            player = nil
    70|        }
    71|    }
