     1|/**
     2| * IVX Project Data Reader (authoritative source: Supabase `jv_deals`)
     3| *
     4| * The public landing page (ivxholding.com) does NOT contain the projects in its
     5| * static HTML — it renders them CLIENT-SIDE from the Supabase `jv_deals` table
     6| * (`sb.from('jv_deals').select('*')`). A plain HTTP fetch of the page therefore
     7| * only sees the static fallback card, never the live project rows. This reader
     8| * queries `jv_deals` directly over the Supabase REST API with the backend
     9| * service-role key so the Owner AI can name the real projects (e.g. "Casa
    10| * Rosario"), list the others, and return per-deal details (location, price,
    11| * ROI, timeline, ownership minimum, media count).
    12| *
    13| * Read-only. The service-role key is never returned. On missing config or a
    14| * failed request it returns an honest `ok:false` with the exact reason / the
    15| * exact missing environment variable.
    16| */
    17|
    18|export type ProjectRecord = {
    19|  id: string;
    20|  name: string;
    21|  location: string | null;
    22|  price: string | null;
    23|  roi: string | null;
    24|  timeline: string | null;
    25|  ownershipMinimum: string | null;
    26|  status: string | null;
    27|  published: boolean;
    28|  mediaCount: number;
    29|};
    30|
    31|export type ProjectDataResult = {
    32|  ok: boolean;
    33|  configured: boolean;
    34|  source: string;
    35|  fetchedAt: string;
    36|  httpStatus: number | null;
    37|  totalRows: number;
    38|  publishedCount: number;
    39|  projects: ProjectRecord[];
    40|  projectNames: string[];
    41|  error: string | null;
    42|  missingEnv: string[];
    43|};
