    45|const TABLE = 'jv_deals';
    46|const FETCH_TIMEOUT_MS = 12_000;
    47|
    48|type RawDeal = Record<string, unknown>;
    49|
    50|function readTrimmed(value: unknown): string {
    51|  return typeof value === 'string' ? value.trim() : '';
    52|}
    53|
    54|function firstString(deal: RawDeal, keys: string[]): string | null {
    55|  for (const key of keys) {
    56|    const value = readTrimmed(deal[key]);
    57|    if (value) {
    58|      return value;
    59|    }
    60|  }
    61|  return null;
    62|}
    63|
    64|function firstNumber(deal: RawDeal, keys: string[]): number | null {
    65|  for (const key of keys) {
    66|    const raw = deal[key];
    67|    const num = typeof raw === 'number' ? raw : typeof raw === 'string' ? Number(raw) : NaN;
    68|    if (Number.isFinite(num) && num > 0) {
    69|      return num;
    70|    }
    71|  }
    72|  return null;
    73|}
    74|
    75|function formatCurrency(value: number | null): string | null {
    76|  if (value === null) {
    77|    return null;
    78|  }
    79|  return `$${value.toLocaleString('en-US')}`;
    80|}
    81|
    82|function countPhotos(deal: RawDeal): number {
    83|  const raw = deal.photos ?? deal.images ?? deal.media;
    84|  if (Array.isArray(raw)) {
    85|    return raw.length;
    86|  }
    87|  if (typeof raw === 'string') {
    88|    try {
    89|      const parsed: unknown = JSON.parse(raw);
    90|      return Array.isArray(parsed) ? parsed.length : 0;
    91|    } catch {
    92|      return 0;
    93|    }
    94|  }
    95|  return 0;
    96|}
    97|
    98|/**
    99| * Normalize a raw `jv_deals` row into a project record. Mirrors the exact
   100| * column fallbacks the landing page renderer uses (snake_case + camelCase).
   101| */
   102|export function normalizeDeal(deal: RawDeal): ProjectRecord {
   103|  const name = firstString(deal, ['title', 'name', 'projectName', 'project_name']) ?? readTrimmed(deal.id) ?? 'Untitled deal';
   104|  const composedLocation = [firstString(deal, ['city']), firstString(deal, ['state']), firstString(deal, ['country'])].filter(Boolean).join(', ');
   105|  const location = firstString(deal, ['propertyAddress', 'property_address', 'addressShort', 'address_short'])
   106|    ?? (composedLocation.length > 0 ? composedLocation : null);
   107|  const roiNum = firstNumber(deal, ['expectedROI', 'expected_roi']);
   108|  const priceNum = firstNumber(deal, ['salePrice', 'sale_price', 'propertyValue', 'property_value', 'estimated_value', 'totalInvestment', 'total_investment', 'amount']);
   109|  const minNum = firstNumber(deal, ['minInvestment', 'min_investment', 'minimum_investment']);
   110|  const publishedRaw = deal.published;
   111|
   112|  return {
   113|    id: readTrimmed(deal.id) || name,
   114|    name,
   115|    location: location !== null && location.length > 0 ? location : null,
   116|    price: formatCurrency(priceNum),
   117|    roi: roiNum === null ? null : `${roiNum}%`,
   118|    timeline: firstString(deal, ['timeline', 'completionTimeline', 'completion_timeline', 'exitStrategy', 'exit_strategy', 'distributionFrequency', 'distribution_frequency']),
   119|    ownershipMinimum: formatCurrency(minNum),
