   124|}
   125|
   126|/** Replicates the landing page's published+active filter (with the same fallbacks). */
   127|export function filterPublishedDeals(deals: RawDeal[]): RawDeal[] {
   128|  const activeStatuses = new Set(['active', 'published', 'live']);
   129|  const isTrashed = (deal: RawDeal): boolean => {
   130|    const status = readTrimmed(deal.status).toLowerCase();
   131|    return status === 'trashed' || status === 'deleted' || status === 'permanently_deleted';
   132|  };
   133|  const isPublished = (deal: RawDeal): boolean => deal.published === true || readTrimmed(deal.published).toLowerCase() === 'true';
   134|
   135|  const visible = deals.filter((deal) => !isTrashed(deal));
   136|  let result = visible.filter((deal) => {
   137|    const status = readTrimmed(deal.status).toLowerCase();
   138|    return isPublished(deal) && (activeStatuses.has(status) || status === '');
   139|  });
   140|  if (result.length === 0) {
   141|    result = visible.filter(isPublished);
   142|  }
   143|  if (result.length === 0) {
   144|    result = visible;
   145|  }
   146|  return result;
   147|}
   148|
   149|function resolveSupabaseConfig(): { url: string; key: string; missing: string[] } {
   150|  const url = readTrimmed(process.env.EXPO_PUBLIC_SUPABASE_URL).replace(/\/+$/, '');
   151|  const key = readTrimmed(process.env.SUPABASE_SERVICE_ROLE_KEY) || readTrimmed(process.env.SUPABASE_SERVICE_KEY);
   152|  const missing: string[] = [];
   153|  if (!url) {
   154|    missing.push('EXPO_PUBLIC_SUPABASE_URL');
   155|  }
   156|  if (!key) {
   157|    missing.push('SUPABASE_SERVICE_ROLE_KEY');
   158|  }
   159|  return { url, key, missing };
   160|}
   161|
   162|/**
   163| * Read the live `jv_deals` rows (authoritative project source) and return the
   164| * published, normalized projects. Read-only over Supabase REST with the
   165| * service-role key. Honest failure on missing config / HTTP error.
   166| */
   167|export async function readLandingProjects(): Promise<ProjectDataResult> {
   168|  const fetchedAt = new Date().toISOString();
   169|  const { url, key, missing } = resolveSupabaseConfig();
   170|  const base: ProjectDataResult = {
   171|    ok: false,
   172|    configured: missing.length === 0,
   173|    source: `supabase:${TABLE}`,
   174|    fetchedAt,
   175|    httpStatus: null,
   176|    totalRows: 0,
   177|    publishedCount: 0,
   178|    projects: [],
   179|    projectNames: [],
   180|    error: null,
   181|    missingEnv: missing,
   182|  };
   183|
   184|  if (missing.length > 0) {
   185|    base.error = `Project data source not configured. Missing backend env: ${missing.join(', ')}.`;
   186|    return base;
   187|  }
   188|
   189|  const controller = new AbortController();
   190|  const timeout = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
   191|  try {
   192|    const endpoint = `${url}/rest/v1/${TABLE}?select=*&order=display_order.asc.nullslast&order=created_at.desc&limit=50`;
   193|    const response = await fetch(endpoint, {
   194|      method: 'GET',
   195|      signal: controller.signal,
   196|      headers: {
   197|        apikey: key,
   198|        Authorization: `Bearer ${key}`,
   199|        Accept: 'application/json',
   200|      },
   201|    });
   202|    clearTimeout(timeout);
   203|    base.httpStatus = response.status;
   204|    if (!response.ok) {
   205|      const body = await response.text().catch(() => '');
   206|      base.error = `Supabase REST returned HTTP ${response.status} for ${TABLE}.${body ? ` ${body.slice(0, 200)}` : ''}`;
   207|      return base;
   208|    }
   209|    const rows = (await response.json()) as RawDeal[];
   210|    const allRows = Array.isArray(rows) ? rows : [];
   211|    const published = filterPublishedDeals(allRows);
   212|    const projects = published.map(normalizeDeal);
   213|    return {
   214|      ...base,
   215|      ok: true,
   216|      totalRows: allRows.length,
   217|      publishedCount: projects.length,
   218|      projects,
   219|      projectNames: projects.map((project) => project.name),
   220|      error: null,
   221|    };
   222|  } catch (error) {
   223|    clearTimeout(timeout);
   224|    const message = error instanceof Error ? error.message : 'unknown error';
   225|    const reason = controller.signal.aborted ? `Request timed out after ${FETCH_TIMEOUT_MS}ms.` : message;
   226|    base.error = `Could not query ${TABLE}: ${reason}`;
   227|    return base;
   228|  }
   229|}

